/* USE : NaverPlaceStatusMapper.getMenuResrceCd */
SELECT  RESRCE_CD
FROM    TB_WB_RESRCE_INFO
WHERE   RESRCE_NM = #{resrceNm}
AND     DISP_LEVEL = 3

