/* NaverPlaceStatusMapper.deleteNaverLink */
DELETE
FROM    TB_CM_NAVER_LINK
WHERE   HQ_OFFICE_CD = #{hqOfficeCd}
AND     STORE_CD = #{storeCd}

/* NaverPlaceStatusMapper.deleteNaverAgreement */
DELETE
FROM    TB_CM_NAVER_LINK_AGREEMENT
WHERE   HQ_OFFICE_CD = #{hqOfficeCd}
AND     STORE_CD = #{storeCd}
